package com.example.rabbitmqconsumer.domain;

import java.time.Instant;

/**
 * Domain model representing an order message received from RabbitMQ.
 *
 * <p>This class is the Java representation of the JSON payload that travels
 * through the message broker. The producer serialises an order to JSON and
 * publishes it; this consumer deserialises the JSON back into an
 * {@code OrderMessage} instance before processing.
 *
 * <h2>Design notes</h2>
 * <ul>
 *   <li><strong>messageId</strong>: a UUID generated by the producer. Consumers
 *       can use it for idempotency checks (i.e. ignore duplicate deliveries that
 *       may occur with at-least-once delivery semantics).</li>
 *   <li><strong>createdAt</strong>: the ISO-8601 timestamp set by the producer
 *       at publish time. Useful for latency measurement and SLA tracking.</li>
 *   <li>The class must have a no-arg constructor and setters so that Jackson
 *       can deserialise the JSON AMQP message body into an instance via
 *       {@link org.springframework.amqp.support.converter.Jackson2JsonMessageConverter}.</li>
 * </ul>
 */
public class OrderMessage {

    /**
     * Unique identifier for this message, generated by the producer.
     * Consumers should store this ID and skip processing of any message
     * with a previously seen ID to achieve idempotent processing.
     */
    private String messageId;

    /**
     * Business identifier for the order.
     * Example: "ORD-20240315-001"
     */
    private String orderId;

    /**
     * Name of the product included in this order.
     * Example: "Wireless Keyboard"
     */
    private String product;

    /**
     * Number of units ordered.
     */
    private int quantity;

    /**
     * ISO-8601 UTC timestamp recording when this message was created by the producer.
     */
    private Instant createdAt;

    // ── Constructors ──────────────────────────────────────────────────────────────

    /**
     * No-arg constructor required by Jackson for JSON deserialisation.
     *
     * <p>Jackson instantiates an empty object and then populates fields via
     * setters. Without this constructor Jackson throws an
     * {@code InvalidDefinitionException} when it tries to deserialise the
     * AMQP message body.
     */
    public OrderMessage() {
    }

    /**
     * All-args constructor — used in tests to build message objects concisely.
     *
     * @param messageId the unique message identifier
     * @param orderId   the business order identifier
     * @param product   the name of the ordered product
     * @param quantity  the number of units ordered
     * @param createdAt the creation timestamp set by the producer
     */
    public OrderMessage(String messageId, String orderId, String product,
                        int quantity, Instant createdAt) {
        this.messageId = messageId;
        this.orderId = orderId;
        this.product = product;
        this.quantity = quantity;
        this.createdAt = createdAt;
    }

    // ── Getters and Setters ───────────────────────────────────────────────────────

    /**
     * @return the unique message identifier (UUID string)
     */
    public String getMessageId() {
        return messageId;
    }

    /**
     * @param messageId the unique message identifier
     */
    public void setMessageId(String messageId) {
        this.messageId = messageId;
    }

    /**
     * @return the business order identifier
     */
    public String getOrderId() {
        return orderId;
    }

    /**
     * @param orderId the business order identifier
     */
    public void setOrderId(String orderId) {
        this.orderId = orderId;
    }

    /**
     * @return the name of the ordered product
     */
    public String getProduct() {
        return product;
    }

    /**
     * @param product the name of the ordered product
     */
    public void setProduct(String product) {
        this.product = product;
    }

    /**
     * @return the number of units ordered
     */
    public int getQuantity() {
        return quantity;
    }

    /**
     * @param quantity the number of units ordered
     */
    public void setQuantity(int quantity) {
        this.quantity = quantity;
    }

    /**
     * @return the ISO-8601 UTC timestamp when the message was published
     */
    public Instant getCreatedAt() {
        return createdAt;
    }

    /**
     * @param createdAt the creation timestamp
     */
    public void setCreatedAt(Instant createdAt) {
        this.createdAt = createdAt;
    }

    /**
     * Human-readable representation useful for logging.
     *
     * @return string form of the order message
     */
    @Override
    public String toString() {
        return "OrderMessage{" +
                "messageId='" + messageId + '\'' +
                ", orderId='" + orderId + '\'' +
                ", product='" + product + '\'' +
                ", quantity=" + quantity +
                ", createdAt=" + createdAt +
                '}';
    }
}
